import{DateTime}from"luxon";import{Converter}from"showdown";(()=>{for(let e of document.getElementsByClassName("date-format"))try{e.innerHTML=DateTime.fromISO(e.innerHTML).toFormat("fff")}catch(e){console.error(e)}})(),(()=>{for(let e of document.getElementsByClassName("markdown-format")){let o=new Converter;try{e.innerHTML=o.makeHtml(e.innerHTML)}catch(e){console.error(e)}}})(),(()=>{for(let e of document.getElementsByClassName("twemoji-format"))try{twemoji.parse(e)}catch(e){console.error(e)}})();